interface User { name: string; }
interface User { age: number; }
// User has BOTH properties - merging!

type Person = { name: string } & { age: number; };

function identity<T>(value: T): T {
  return value;
}

const num = identity(42);       // type: number
const str = identity("hello"); // type: string

interface User {
  name: string;
  age: number;
  email: string;
}

type PartialUser = Partial<User>;
// Equivalent to:
// { name?: string; age?: number; email?: string; }

function print(value: string | number) {
  if (typeof value === "string") {
    console.log(value.toUpperCase()); // value is string
  } else {
    console.log(value.toFixed(2));    // value is number
  }
}

type ID = string | number;

function getId(id: ID): string {
  return id.toString(); // works on both
}

const userId: ID = "abc123";
const numericId: ID = 42;

// Interface allows declaration merging
interface Window { title: string; }
interface Window { ts: TypeScript; }

// Type alias for unions
type ID = string | number;

// Type for computed properties
type Keys = "firstName" | "lastName";

interface HasLength {
  length: number;
}

function logLength<T extends HasLength>(arg: T): number {
  return arg.length; // Safe - T has length
}

logLength("hello");     // string has length
logLength([1, 2, 3]);    // array has length
logLength(123);          // Error: number doesn't have length

interface User {
  id: number;
  name: string;
  email: string;
  createdAt: Date;
}

type UserPreview = Pick<User, "id" | "name">;
// { id: number; name: string; }

type UserWithoutTimestamps = Omit<User, "createdAt">;
// { id: number; name: string; email: string; }

type Readonly<T> = {
  readonly [K in keyof T]: T[K];
};

type Optional<T> = {
  [K in keyof T]?: T[K];
};

interface User {
  name: string;
  age: number;
}

type ReadonlyUser = Readonly<User>;
type OptionalUser = Optional<User>;

function throwError(msg: string): never {
  throw new Error(msg);
}

function process(value: string | number) {
  if (typeof value === "string") {
    return value;
  } else if (typeof value === "number") {
    return value;
  } else {
    // value is never here - exhaustive check
    throwError("Unexpected value: " + value);
  }
}

function processAny(value: any): void {
  value.toUpperCase(); // Works - no safety
}

function processUnknown(value: unknown): void {
  // value.toUpperCase(); // Error!

  if (typeof value === "string") {
    value.toUpperCase(); // OK after narrowing
  }
}

type IsString<T> = T extends string ? true : false;

type A = IsString<string>;  // true
type B = IsString<number>;   // false

// Extract return type with infer
type ReturnType<T> = T extends (...args: any[]) => infer R ? R : never;

type R = ReturnType<() => number>; // number

type EventName = `on${string}`;

type CSSProp = `${string}-${string}`;

type Action = "set" | "get";
type APIEndpoint = `${Action}${string}`;
// "setUser" | "setData" | "getUser" | "getData"...

const event: EventName = "onClick"; // OK
const prop: CSSProp = "background-color"; // OK

type ArrayElement<T> = T extends (infer U)[] ? U : never;

type StrArr = string[];
type NumArr = number[];

type Str = ArrayElement<StrArr>;  // string
type Num = ArrayElement<NumArr>; // number

// Extract promise result type
type Awaited<T> = T extends Promise<infer U> ? U : never;
type Result = Awaited<Promise<string>>; // string

type RemoveKind<T> = {
  [K in keyof T as Exclude<K, "kind">]: T[K];
};

type MakeOptional<T> = {
  [K in keyof T]?: T[K];
};

type PrefixKeys<T> = {
  [K in keyof T as `get${Capitalize<string & K>}`]: T[K];
};

interface User { name: string; age: number; }
type Prefixed = PrefixKeys<User>;
// { getName: string; getAge: number; }
